def risk_color(r):
    r = str(r).upper()
    if "ALTO" in r:   return C_RED
    if "MEDIO" in r:  return C_AMBER
    return C_GREEN

def fmt_money(v):
    try:
        v = float(v)
        return f"${v:,.2f}" if v >= 0 else f"-${abs(v):,.2f}"
    except:
        return str(v)

